/**
 * Pre-build the ViewGraph bundle for npm publishing.
 *
 * When installed from npm, the extension source files aren't available.
 * This script runs at prepublishOnly time to bake the bundle into a
 * static JS file that bundle.js falls back to when the source files
 * are missing.
 *
 * Run: node build-bundle.js
 */

import { writeFile } from 'fs/promises';
import { buildBundle } from './bundle.js';

const bundle = await buildBundle();
const output = `// Auto-generated by build-bundle.js - do not edit\nexport const PREBUILT_BUNDLE = ${JSON.stringify(bundle)};\n`;
await writeFile(new URL('./bundle-prebuilt.js', import.meta.url), output);
console.log(`Bundle pre-built: ${(bundle.length / 1024).toFixed(1)}KB`);
